mapper.delete:
/* com.educare.edu.comn.mapper.FeedbackOpenAnswerMapper.deleteByFbIdxUserId */
	delete from t_feedback_open_answer
	where open_idx=#{openIdx} and fb_idx=#{fbIdx} and user_id=#{userId}

mapper.select:
/* com.educare.edu.comn.mapper.FeedbackOpenAnswerMapper.selectBy_FbIdx_QtIdx_UserIdx */
	select * from t_feedback_open_answer
	where open_idx=#{openIdx} and fb_idx=#{fbIdx} and qt_idx=#{qtIdx} and user_id=#{userId}

/* com.educare.edu.comn.mapper.FeedbackOpenAnswerMapper.selectCntByOpenIdx */
	select count(*) from (
		select open_idx,user_id
		from t_feedback_open_answer
		where open_idx=#{openIdx}
		group by open_idx,user_id
	) a
